ScoringLogic:
import numpy as np
# Input arrays: m123, pt, eta, score_xgb, r_ab, dr_ab (all 1-D numpy arrays, same length)
# Mass Gaussian: central value 173 GeV, width ~20 GeV
def mass_gauss(m):
    return np.exp(-0.5*((m-173)/20)**2)
# pt Gaussian: peak around 400 GeV, width ~150 GeV
def pt_gauss(p):
    return np.exp(-0.5*((p-400)/150)**2)
# Eta penalty: prefers central jets
def eta_penalty(e):
    return np.exp(-np.abs(e)/2)
# Angular distance penalties for the two-jet pair (r_ab) and ΔR (dr_ab)
def angle_factor(r, dr):
    return np.exp(-r/0.5) * np.exp(-dr/0.5)
# Final combined score for each candidate
final_scores = score_xgb * mass_gauss(m123) * pt_gauss(pt) * eta_penalty(eta) * angle_factor(r_ab, dr_ab)

