    w[0]*m123 + w[1]*pt + w[2]*eta + w[3]*score_xgb + w[4]*r_ab + w[5]*dr_ab
)

h2 = np.maximum(0,
    w[6]*h1 + w[7]*score_xgb + w[8]*r_ab
)

h3 = np.exp(
    w[9]*h2 + w[10]*dr_ab
)

final_scores = w[11] + w[12]*h1 + w[13]*h2 + w[14]*h3
